"use strict";const o=require("../utils/request.js");exports.applySharedBooking=function(e,t){return o.post(`/bookings/shared/${e}/apply`,t)},exports.cancelBooking=function(e){return o.put(`/bookings/${e}/cancel`)},exports.createBooking=function(e){return o.post("/bookings",e)},exports.createSharedBooking=function(e){return o.post("/bookings/shared",e)},exports.getBookingDetail=function(e){return o.get(`/bookings/${e}`)},exports.getVenueAvailableSlots=function(e,t){return o.get(`/bookings/venues/${e}/slots`,{date:t})};
